// ss Phase 1: 기본 소켓 정보 조회
// 목표: 활성 네트워크 연결 정보 표시, 소켓 상태 조회

// === 타입 정의 ===

type SocketID = u64
type IpAddr = string
type Port = u16
type Timestamp = u64

enum SocketState {
    Listen              // 대기 중
    Established         // 연결됨
    TimeWait            // 시간 대기
    Closed              // 종료됨
    SynSent             // SYN 전송
    SynRecv             // SYN 수신
}

enum Protocol {
    TCP
    UDP
    SCTP
}

type Socket {
    id: SocketID
    protocol: Protocol
    local_ip: IpAddr
    local_port: Port
    remote_ip: IpAddr
    remote_port: Port
    state: SocketState
    created_at: Timestamp
}

type SocketManager {
    sockets: Vec<Socket>
    next_id: SocketID
}

// === SocketManager 구현 ===

impl SocketManager {

    // 새 SocketManager 생성
    fn new() -> SocketManager {
        SocketManager {
            sockets: Vec::new(),
            next_id: 1000u64
        }
    }

    // 소켓 추가
    fn add_socket(mut self, protocol: Protocol, local_ip: IpAddr, local_port: Port,
                  remote_ip: IpAddr, remote_port: Port, state: SocketState) -> (SocketManager, SocketID) {
        let socket_id = self.next_id
        self.next_id = self.next_id + 1u64

        let socket = Socket {
            id: socket_id,
            protocol: protocol,
            local_ip: local_ip,
            local_port: local_port,
            remote_ip: remote_ip,
            remote_port: remote_port,
            state: state,
            created_at: get_timestamp()
        }

        self.sockets.push(socket)
        (self, socket_id)
    }

    // 모든 소켓 조회
    fn list_all_sockets(ref self) -> Vec<(SocketID, IpAddr, Port, IpAddr, Port, string)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    let state_str = socket_state_to_string(s.state)
                    result.push((s.id, s.local_ip, s.local_port, s.remote_ip, s.remote_port, state_str))
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 프로토콜별 소켓 조회
    fn list_sockets_by_protocol(ref self, protocol: Protocol) -> Vec<(SocketID, IpAddr, Port, IpAddr, Port)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if protocol_match(s.protocol, protocol) {
                        result.push((s.id, s.local_ip, s.local_port, s.remote_ip, s.remote_port))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 특정 포트 조회
    fn find_socket_by_local_port(ref self, port: Port) -> Option<(SocketID, IpAddr, IpAddr, Port, string)> {
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if s.local_port == port {
                        let state_str = socket_state_to_string(s.state)
                        return Some((s.id, s.local_ip, s.remote_ip, s.remote_port, state_str))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 소켓 정보 상세 조회
    fn get_socket_details(ref self, socket_id: SocketID) -> Option<(IpAddr, Port, IpAddr, Port, string, Timestamp)> {
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if s.id == socket_id {
                        let state_str = socket_state_to_string(s.state)
                        return Some((s.local_ip, s.local_port, s.remote_ip, s.remote_port, state_str, s.created_at))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 총 소켓 수
    fn total_socket_count(ref self) -> u64 {
        self.sockets.len()
    }

    // TCP 소켓 수
    fn tcp_socket_count(ref self) -> u64 {
        let mut count = 0u64
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    match s.protocol {
                        Protocol::TCP => {
                            count = count + 1u64
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        count
    }

    // UDP 소켓 수
    fn udp_socket_count(ref self) -> u64 {
        let mut count = 0u64
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    match s.protocol {
                        Protocol::UDP => {
                            count = count + 1u64
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        count
    }
}

// === 유틸리티 함수 ===

fn get_timestamp() -> Timestamp {
    12345678u64
}

fn socket_state_to_string(state: SocketState) -> string {
    match state {
        SocketState::Listen => "LISTEN"
        SocketState::Established => "ESTABLISHED"
        SocketState::TimeWait => "TIME_WAIT"
        SocketState::Closed => "CLOSED"
        SocketState::SynSent => "SYN_SENT"
        SocketState::SynRecv => "SYN_RECV"
    }
}

fn protocol_to_string(proto: Protocol) -> string {
    match proto {
        Protocol::TCP => "tcp"
        Protocol::UDP => "udp"
        Protocol::SCTP => "sctp"
    }
}

fn protocol_match(p1: Protocol, p2: Protocol) -> bool {
    match p1 {
        Protocol::TCP => match p2 {
            Protocol::TCP => true
            _ => false
        }
        Protocol::UDP => match p2 {
            Protocol::UDP => true
            _ => false
        }
        Protocol::SCTP => match p2 {
            Protocol::SCTP => true
            _ => false
        }
    }
}

// === 테스트 ===

fn main() {
    println!("=== ss Phase 1: 기본 소켓 정보 ===")

    let mut mgr = SocketManager::new()

    // 소켓 추가
    let (mgr2, sock1) = mgr.add_socket(
        Protocol::TCP,
        "127.0.0.1",
        8080u16,
        "0.0.0.0",
        0u16,
        SocketState::Listen
    )
    mgr = mgr2
    println!("✅ TCP 소켓 추가: 127.0.0.1:8080 (ID: " ++ sock1.to_string() ++ ")")

    let (mgr2, sock2) = mgr.add_socket(
        Protocol::TCP,
        "192.168.1.100",
        55000u16,
        "8.8.8.8",
        443u16,
        SocketState::Established
    )
    mgr = mgr2
    println!("✅ TCP 소켓 추가: 192.168.1.100:55000 -> 8.8.8.8:443 (ID: " ++ sock2.to_string() ++ ")")

    let (mgr2, sock3) = mgr.add_socket(
        Protocol::UDP,
        "0.0.0.0",
        53u16,
        "0.0.0.0",
        0u16,
        SocketState::Listen
    )
    mgr = mgr2
    println!("✅ UDP 소켓 추가: 0.0.0.0:53 (ID: " ++ sock3.to_string() ++ ")")

    // 모든 소켓 조회
    println!("\n📋 모든 소켓:")
    let all_sockets = mgr.list_all_sockets()
    let mut i = 0u64
    while i < all_sockets.len() {
        let (id, lip, lport, rip, rport, state) = all_sockets.get(i).unwrap()
        println!("  [" ++ id.to_string() ++ "] " ++ lip ++ ":" ++ lport.to_string() ++ " -> " ++ rip ++ ":" ++ rport.to_string() ++ " (" ++ state ++ ")")
        i = i + 1u64
    }

    // TCP 소켓만 조회
    println!("\n📋 TCP 소켓:")
    let tcp_sockets = mgr.list_sockets_by_protocol(Protocol::TCP)
    let mut i = 0u64
    while i < tcp_sockets.len() {
        let (id, lip, lport, rip, rport) = tcp_sockets.get(i).unwrap()
        println!("  [" ++ id.to_string() ++ "] " ++ lip ++ ":" ++ lport.to_string() ++ " -> " ++ rip ++ ":" ++ rport.to_string())
        i = i + 1u64
    }

    // 포트 조회
    println!("\n🔍 포트 8080 조회:")
    let port_info = mgr.find_socket_by_local_port(8080u16)
    match port_info {
        Some((id, lip, rip, rport, state)) => {
            println!("  [" ++ id.to_string() ++ "] " ++ lip ++ " -> " ++ rip ++ ":" ++ rport.to_string() ++ " (" ++ state ++ ")")
        }
        None => {
            println!("  포트를 찾을 수 없음")
        }
    }

    // 통계
    println!("\n📊 소켓 통계:")
    println!("  총 소켓: " ++ mgr.total_socket_count().to_string())
    println!("  TCP: " ++ mgr.tcp_socket_count().to_string())
    println!("  UDP: " ++ mgr.udp_socket_count().to_string())
}

// ss Phase 2: 상태별 필터링
// 목표: 소켓 상태 기반 필터링, 고급 조회 기능

// === 타입 정의 ===

type SocketID = u64
type IpAddr = string
type Port = u16
type Timestamp = u64

enum SocketState {
    Listen
    Established
    TimeWait
    Closed
    SynSent
    SynRecv
}

enum Protocol {
    TCP
    UDP
    SCTP
}

type Socket {
    id: SocketID
    protocol: Protocol
    local_ip: IpAddr
    local_port: Port
    remote_ip: IpAddr
    remote_port: Port
    state: SocketState
    created_at: Timestamp
}

type SocketFilter {
    state: Option<SocketState>
    protocol: Option<Protocol>
    local_port: Option<Port>
}

type SocketManager {
    sockets: Vec<Socket>
    next_id: SocketID
}

// === SocketManager 구현 ===

impl SocketManager {

    fn new() -> SocketManager {
        SocketManager {
            sockets: Vec::new(),
            next_id: 1000u64
        }
    }

    fn add_socket(mut self, protocol: Protocol, local_ip: IpAddr, local_port: Port,
                  remote_ip: IpAddr, remote_port: Port, state: SocketState) -> (SocketManager, SocketID) {
        let socket_id = self.next_id
        self.next_id = self.next_id + 1u64

        let socket = Socket {
            id: socket_id,
            protocol: protocol,
            local_ip: local_ip,
            local_port: local_port,
            remote_ip: remote_ip,
            remote_port: remote_port,
            state: state,
            created_at: get_timestamp()
        }

        self.sockets.push(socket)
        (self, socket_id)
    }

    // 상태로 필터링
    fn filter_by_state(ref self, state: SocketState) -> Vec<(SocketID, IpAddr, Port, IpAddr, Port)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if state_match(s.state, state) {
                        result.push((s.id, s.local_ip, s.local_port, s.remote_ip, s.remote_port))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 프로토콜과 상태로 필터링
    fn filter_by_protocol_and_state(ref self, protocol: Protocol, state: SocketState) -> Vec<(SocketID, IpAddr, Port, IpAddr, Port)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if protocol_match(s.protocol, protocol) && state_match(s.state, state) {
                        result.push((s.id, s.local_ip, s.local_port, s.remote_ip, s.remote_port))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 대기 중인 소켓 조회
    fn find_listening_sockets(ref self) -> Vec<(SocketID, IpAddr, Port, string)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    match s.state {
                        SocketState::Listen => {
                            let proto = protocol_to_string(s.protocol)
                            result.push((s.id, s.local_ip, s.local_port, proto))
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 연결된 소켓 조회
    fn find_established_sockets(ref self) -> Vec<(SocketID, IpAddr, Port, IpAddr, Port)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    match s.state {
                        SocketState::Established => {
                            result.push((s.id, s.local_ip, s.local_port, s.remote_ip, s.remote_port))
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // IP 주소로 필터링
    fn filter_by_local_ip(ref self, ip: IpAddr) -> Vec<(SocketID, Port, IpAddr, Port, string)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if string_equal(s.local_ip, ip) {
                        let state = socket_state_to_string(s.state)
                        result.push((s.id, s.local_port, s.remote_ip, s.remote_port, state))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // TIME_WAIT 상태 소켓 조회
    fn find_time_wait_sockets(ref self) -> Vec<(SocketID, IpAddr, Port, IpAddr, Port, u64)> {
        let mut result = Vec::new()
        let now = get_timestamp()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    match s.state {
                        SocketState::TimeWait => {
                            let age = now - s.created_at
                            result.push((s.id, s.local_ip, s.local_port, s.remote_ip, s.remote_port, age))
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 상태별 통계
    fn count_by_state(ref self, state: SocketState) -> u64 {
        let mut count = 0u64
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if state_match(s.state, state) {
                        count = count + 1u64
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        count
    }

    // 포트 범위로 필터링
    fn filter_by_port_range(ref self, min_port: Port, max_port: Port) -> Vec<(SocketID, IpAddr, Port, string)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if s.local_port >= min_port && s.local_port <= max_port {
                        let state = socket_state_to_string(s.state)
                        result.push((s.id, s.local_ip, s.local_port, state))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }
}

// === 유틸리티 함수 ===

fn get_timestamp() -> Timestamp {
    12345678u64
}

fn socket_state_to_string(state: SocketState) -> string {
    match state {
        SocketState::Listen => "LISTEN"
        SocketState::Established => "ESTABLISHED"
        SocketState::TimeWait => "TIME_WAIT"
        SocketState::Closed => "CLOSED"
        SocketState::SynSent => "SYN_SENT"
        SocketState::SynRecv => "SYN_RECV"
    }
}

fn protocol_to_string(proto: Protocol) -> string {
    match proto {
        Protocol::TCP => "tcp"
        Protocol::UDP => "udp"
        Protocol::SCTP => "sctp"
    }
}

fn protocol_match(p1: Protocol, p2: Protocol) -> bool {
    match p1 {
        Protocol::TCP => match p2 {
            Protocol::TCP => true
            _ => false
        }
        Protocol::UDP => match p2 {
            Protocol::UDP => true
            _ => false
        }
        Protocol::SCTP => match p2 {
            Protocol::SCTP => true
            _ => false
        }
    }
}

fn state_match(s1: SocketState, s2: SocketState) -> bool {
    match s1 {
        SocketState::Listen => match s2 {
            SocketState::Listen => true
            _ => false
        }
        SocketState::Established => match s2 {
            SocketState::Established => true
            _ => false
        }
        SocketState::TimeWait => match s2 {
            SocketState::TimeWait => true
            _ => false
        }
        SocketState::Closed => match s2 {
            SocketState::Closed => true
            _ => false
        }
        SocketState::SynSent => match s2 {
            SocketState::SynSent => true
            _ => false
        }
        SocketState::SynRecv => match s2 {
            SocketState::SynRecv => true
            _ => false
        }
    }
}

fn string_equal(s1: string, s2: string) -> bool {
    s1 == s2
}

