// ss Phase 3: 통계 계산
// 목표: 네트워크 통계, 대역폭 분석, 연결 통계

// === 타입 정의 ===

type SocketID = u64
type IpAddr = string
type Port = u16
type Timestamp = u64
type ByteCount = u64

enum SocketState {
    Listen
    Established
    TimeWait
    Closed
    SynSent
    SynRecv
}

enum Protocol {
    TCP
    UDP
    SCTP
}

type Socket {
    id: SocketID
    protocol: Protocol
    local_ip: IpAddr
    local_port: Port
    remote_ip: IpAddr
    remote_port: Port
    state: SocketState
    created_at: Timestamp
    bytes_sent: ByteCount
    bytes_recv: ByteCount
}

type NetworkStats {
    total_sockets: u64
    tcp_sockets: u64
    udp_sockets: u64
    listen_sockets: u64
    established_sockets: u64
    time_wait_sockets: u64
    total_bytes_sent: ByteCount
    total_bytes_recv: ByteCount
    avg_connection_age: u64
}

type SocketManager {
    sockets: Vec<Socket>
    next_id: SocketID
}

// === SocketManager 구현 ===

impl SocketManager {

    fn new() -> SocketManager {
        SocketManager {
            sockets: Vec::new(),
            next_id: 1000u64
        }
    }

    fn add_socket(mut self, protocol: Protocol, local_ip: IpAddr, local_port: Port,
                  remote_ip: IpAddr, remote_port: Port, state: SocketState,
                  bytes_sent: ByteCount, bytes_recv: ByteCount) -> (SocketManager, SocketID) {
        let socket_id = self.next_id
        self.next_id = self.next_id + 1u64

        let socket = Socket {
            id: socket_id,
            protocol: protocol,
            local_ip: local_ip,
            local_port: local_port,
            remote_ip: remote_ip,
            remote_port: remote_port,
            state: state,
            created_at: get_timestamp(),
            bytes_sent: bytes_sent,
            bytes_recv: bytes_recv
        }

        self.sockets.push(socket)
        (self, socket_id)
    }

    // 전체 통계 계산
    fn calculate_stats(ref self) -> NetworkStats {
        let mut tcp_count = 0u64
        let mut udp_count = 0u64
        let mut listen_count = 0u64
        let mut est_count = 0u64
        let mut tw_count = 0u64
        let mut total_sent = 0u64
        let mut total_recv = 0u64
        let mut total_age = 0u64
        let now = get_timestamp()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    // 프로토콜 통계
                    match s.protocol {
                        Protocol::TCP => { tcp_count = tcp_count + 1u64 }
                        Protocol::UDP => { udp_count = udp_count + 1u64 }
                        _ => {}
                    }

                    // 상태 통계
                    match s.state {
                        SocketState::Listen => { listen_count = listen_count + 1u64 }
                        SocketState::Established => { est_count = est_count + 1u64 }
                        SocketState::TimeWait => { tw_count = tw_count + 1u64 }
                        _ => {}
                    }

                    // 데이터 통계
                    total_sent = total_sent + s.bytes_sent
                    total_recv = total_recv + s.bytes_recv
                    let age = now - s.created_at
                    total_age = total_age + age
                }
                None => {}
            }

            i = i + 1u64
        }

        let total_sockets = self.sockets.len()
        let avg_age = if total_sockets > 0u64 {
            total_age / total_sockets
        } else {
            0u64
        }

        NetworkStats {
            total_sockets: total_sockets,
            tcp_sockets: tcp_count,
            udp_sockets: udp_count,
            listen_sockets: listen_count,
            established_sockets: est_count,
            time_wait_sockets: tw_count,
            total_bytes_sent: total_sent,
            total_bytes_recv: total_recv,
            avg_connection_age: avg_age
        }
    }

    // 연결별 데이터 전송량
    fn get_connection_bandwidth(ref self, socket_id: SocketID) -> Option<(ByteCount, ByteCount, ByteCount)> {
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if s.id == socket_id {
                        let total = s.bytes_sent + s.bytes_recv
                        return Some((s.bytes_sent, s.bytes_recv, total))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 상위 N개 연결 (데이터 전송량)
    fn get_top_connections(ref self, limit: u64) -> Vec<(SocketID, IpAddr, Port, ByteCount)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    let total_bytes = s.bytes_sent + s.bytes_recv
                    result.push((s.id, s.remote_ip, s.remote_port, total_bytes))
                }
                None => {}
            }

            i = i + 1u64
        }

        // 간단한 정렬 (버블 정렬)
        let mut sorted = result
        let mut done = false

        while !done {
            done = true
            let mut j = 0u64

            while j + 1u64 < sorted.len() {
                let (_, _, _, bytes1) = sorted.get(j).unwrap()
                let (_, _, _, bytes2) = sorted.get(j + 1u64).unwrap()

                if bytes1 < bytes2 {
                    let temp1 = sorted.get(j).unwrap()
                    let temp2 = sorted.get(j + 1u64).unwrap()
                    sorted.set(j, temp2)
                    sorted.set(j + 1u64, temp1)
                    done = false
                }

                j = j + 1u64
            }
        }

        // 상위 limit개 반환
        let mut top = Vec::new()
        let mut i = 0u64

        while i < limit && i < sorted.len() {
            let conn = sorted.get(i)

            match conn {
                Some(c) => {
                    top.push(c)
                }
                None => {}
            }

            i = i + 1u64
        }

        top
    }

    // 프로토콜별 데이터량
    fn get_protocol_stats(ref self) -> Vec<(string, u64, ByteCount)> {
        let mut tcp_count = 0u64
        let mut udp_count = 0u64
        let mut tcp_bytes = 0u64
        let mut udp_bytes = 0u64
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    let total_bytes = s.bytes_sent + s.bytes_recv

                    match s.protocol {
                        Protocol::TCP => {
                            tcp_count = tcp_count + 1u64
                            tcp_bytes = tcp_bytes + total_bytes
                        }
                        Protocol::UDP => {
                            udp_count = udp_count + 1u64
                            udp_bytes = udp_bytes + total_bytes
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        let mut result = Vec::new()
        result.push(("TCP", tcp_count, tcp_bytes))
        result.push(("UDP", udp_count, udp_bytes))

        result
    }

    // 상태별 통계
    fn get_state_distribution(ref self) -> Vec<(string, u64)> {
        let mut listen = 0u64
        let mut est = 0u64
        let mut tw = 0u64
        let mut closed = 0u64
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    match s.state {
                        SocketState::Listen => { listen = listen + 1u64 }
                        SocketState::Established => { est = est + 1u64 }
                        SocketState::TimeWait => { tw = tw + 1u64 }
                        SocketState::Closed => { closed = closed + 1u64 }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        let mut result = Vec::new()
        result.push(("LISTEN", listen))
        result.push(("ESTABLISHED", est))
        result.push(("TIME_WAIT", tw))
        result.push(("CLOSED", closed))

        result
    }

    // 평균 연결 나이
    fn get_average_connection_age(ref self) -> u64 {
        if self.sockets.len() == 0u64 {
            return 0u64
        }

        let now = get_timestamp()
        let mut total_age = 0u64
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    let age = now - s.created_at
                    total_age = total_age + age
                }
                None => {}
            }

            i = i + 1u64
        }

        total_age / self.sockets.len()
    }
}

