// ss Phase 4: 고급 분석
// 목표: 연결 추적, 이상 탐지, 성능 분석, 네트워크 진단

// === 타입 정의 ===

type SocketID = u64
type IpAddr = string
type Port = u16
type Timestamp = u64
type ByteCount = u64

enum SocketState {
    Listen
    Established
    TimeWait
    Closed
    SynSent
    SynRecv
}

enum Protocol {
    TCP
    UDP
    SCTP
}

enum ConnectionType {
    Inbound
    Outbound
    Local
}

type Socket {
    id: SocketID
    protocol: Protocol
    local_ip: IpAddr
    local_port: Port
    remote_ip: IpAddr
    remote_port: Port
    state: SocketState
    created_at: Timestamp
    bytes_sent: ByteCount
    bytes_recv: ByteCount
    retransmits: u64
}

type ConnectionAnalysis {
    socket_id: SocketID
    conn_type: ConnectionType
    is_healthy: bool
    avg_throughput: u64
    retransmit_rate: u64
    duration: u64
}

type AnomalyDetection {
    has_anomaly: bool
    anomaly_type: string
    description: string
    severity: u64
}

type SocketManager {
    sockets: Vec<Socket>
    next_id: SocketID
}

// === SocketManager 구현 ===

impl SocketManager {

    fn new() -> SocketManager {
        SocketManager {
            sockets: Vec::new(),
            next_id: 1000u64
        }
    }

    fn add_socket(mut self, protocol: Protocol, local_ip: IpAddr, local_port: Port,
                  remote_ip: IpAddr, remote_port: Port, state: SocketState,
                  bytes_sent: ByteCount, bytes_recv: ByteCount, retransmits: u64) -> (SocketManager, SocketID) {
        let socket_id = self.next_id
        self.next_id = self.next_id + 1u64

        let socket = Socket {
            id: socket_id,
            protocol: protocol,
            local_ip: local_ip,
            local_port: local_port,
            remote_ip: remote_ip,
            remote_port: remote_port,
            state: state,
            created_at: get_timestamp(),
            bytes_sent: bytes_sent,
            bytes_recv: bytes_recv,
            retransmits: retransmits
        }

        self.sockets.push(socket)
        (self, socket_id)
    }

    // 연결 유형 결정
    fn determine_connection_type(ref self, socket_id: SocketID) -> Option<ConnectionType> {
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if s.id == socket_id {
                        if is_loopback_ip(s.local_ip) && is_loopback_ip(s.remote_ip) {
                            return Some(ConnectionType::Local)
                        } else if is_loopback_ip(s.local_ip) || is_private_ip(s.local_ip) {
                            if is_loopback_ip(s.remote_ip) || is_private_ip(s.remote_ip) {
                                return Some(ConnectionType::Local)
                            } else {
                                return Some(ConnectionType::Outbound)
                            }
                        } else {
                            return Some(ConnectionType::Inbound)
                        }
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 연결 분석
    fn analyze_connection(ref self, socket_id: SocketID) -> Option<ConnectionAnalysis> {
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if s.id == socket_id {
                        let now = get_timestamp()
                        let duration = now - s.created_at

                        let total_bytes = s.bytes_sent + s.bytes_recv
                        let throughput = if duration > 0u64 {
                            total_bytes / duration
                        } else {
                            0u64
                        }

                        let retransmit_rate = if total_bytes > 0u64 {
                            (s.retransmits * 100u64) / total_bytes
                        } else {
                            0u64
                        }

                        let is_healthy = retransmit_rate < 5u64

                        let conn_type = match self.determine_connection_type(socket_id) {
                            Some(ct) => ct
                            None => ConnectionType::Local
                        }

                        return Some(ConnectionAnalysis {
                            socket_id: socket_id,
                            conn_type: conn_type,
                            is_healthy: is_healthy,
                            avg_throughput: throughput,
                            retransmit_rate: retransmit_rate,
                            duration: duration
                        })
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 이상 탐지
    fn detect_anomalies(ref self, socket_id: SocketID) -> AnomalyDetection {
        let mut anomaly = AnomalyDetection {
            has_anomaly: false,
            anomaly_type: "NONE",
            description: "정상",
            severity: 0u64
        }

        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    if s.id == socket_id {
                        // 재전송율 확인
                        let total_bytes = s.bytes_sent + s.bytes_recv
                        if total_bytes > 0u64 {
                            let retransmit_rate = (s.retransmits * 100u64) / total_bytes

                            if retransmit_rate > 20u64 {
                                anomaly = AnomalyDetection {
                                    has_anomaly: true,
                                    anomaly_type: "HIGH_RETRANSMIT",
                                    description: "높은 재전송율 감지",
                                    severity: 3u64
                                }
                                return anomaly
                            }
                        }

                        // TIME_WAIT 상태 이상
                        match s.state {
                            SocketState::TimeWait => {
                                let now = get_timestamp()
                                let age = now - s.created_at
                                if age > 7200u64 {
                                    anomaly = AnomalyDetection {
                                        has_anomaly: true,
                                        anomaly_type: "LONG_TIME_WAIT",
                                        description: "TIME_WAIT 상태가 너무 길음",
                                        severity: 2u64
                                    }
                                    return anomaly
                                }
                            }
                            _ => {}
                        }

                        // 단방향 통신 확인
                        if (s.bytes_sent == 0u64 || s.bytes_recv == 0u64) && s.bytes_sent + s.bytes_recv > 0u64 {
                            match s.state {
                                SocketState::Established => {
                                    anomaly = AnomalyDetection {
                                        has_anomaly: true,
                                        anomaly_type: "UNIDIRECTIONAL_FLOW",
                                        description: "한방향 데이터 흐름 감지",
                                        severity: 1u64
                                    }
                                    return anomaly
                                }
                                _ => {}
                            }
                        }
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        anomaly
    }

    // 성능 진단
    fn diagnose_performance(ref self) -> Vec<(string, u64)> {
        let mut diagnostics = Vec::new()
        let mut high_retransmit_count = 0u64
        let mut stalled_connections = 0u64
        let mut low_throughput_count = 0u64
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    // 재전송 문제
                    let total_bytes = s.bytes_sent + s.bytes_recv
                    if total_bytes > 0u64 {
                        let retransmit_rate = (s.retransmits * 100u64) / total_bytes
                        if retransmit_rate > 10u64 {
                            high_retransmit_count = high_retransmit_count + 1u64
                        }
                    }

                    // 정체된 연결
                    match s.state {
                        SocketState::Established => {
                            if s.bytes_sent == 0u64 && s.bytes_recv == 0u64 {
                                stalled_connections = stalled_connections + 1u64
                            }
                        }
                        _ => {}
                    }

                    // 저대역폭
                    let now = get_timestamp()
                    let duration = now - s.created_at
                    if duration > 60u64 {
                        let throughput = total_bytes / duration
                        if throughput < 1024u64 && total_bytes > 0u64 {
                            low_throughput_count = low_throughput_count + 1u64
                        }
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        diagnostics.push(("높은_재전송율", high_retransmit_count))
        diagnostics.push(("정체된_연결", stalled_connections))
        diagnostics.push(("저대역폭", low_throughput_count))

        diagnostics
    }

    // 활성 연결 수
    fn get_active_connections(ref self) -> u64 {
        let mut count = 0u64
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    match s.state {
                        SocketState::Established => {
                            count = count + 1u64
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        count
    }

    // 비정상 연결 찾기
    fn find_unhealthy_connections(ref self) -> Vec<(SocketID, IpAddr, Port, u64)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.sockets.len() {
            let sock = self.sockets.get(i)

            match sock {
                Some(s) => {
                    let analysis = self.analyze_connection(s.id)

                    match analysis {
                        Some(a) => {
                            if !a.is_healthy {
                                result.push((s.id, s.remote_ip, s.remote_port, a.retransmit_rate))
                            }
                        }
                        None => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }
}

// === 유틸리티 함수 ===

fn get_timestamp() -> Timestamp {
    12345678u64
}

fn is_loopback_ip(ip: IpAddr) -> bool {
    ip == "127.0.0.1" || ip == "::1"
}

fn is_private_ip(ip: IpAddr) -> bool {
    ip == "0.0.0.0" ||
    ip == "192.168.1.100" ||
    ip == "10.0.0.0" ||
    ip == "172.16.0.0"
}

fn connection_type_to_string(ct: ConnectionType) -> string {
    match ct {
        ConnectionType::Inbound => "인바운드"
        ConnectionType::Outbound => "아웃바운드"
        ConnectionType::Local => "로컬"
    }
}

