// route Phase 1: 기본 라우팅 정보
// 목표: 라우팅 테이블 조회, 기본 경로 추가/삭제

// === 타입 정의 ===

type RouteID = u64
type IpAddr = string
type Netmask = string
type Gateway = string
type Metric = u32
type Timestamp = u64

enum RouteType {
    Host              // 호스트 경로
    Network           // 네트워크 경로
    Default           // 기본 경로
    Local             // 로컬 경로
}

type Route {
    id: RouteID
    destination: IpAddr
    netmask: Netmask
    gateway: Gateway
    metric: Metric
    route_type: RouteType
    interface: string
    created_at: Timestamp
    active: bool
}

type RouteTable {
    routes: Vec<Route>
    next_id: RouteID
}

// === RouteTable 구현 ===

impl RouteTable {

    // 새 라우팅 테이블 생성
    fn new() -> RouteTable {
        RouteTable {
            routes: Vec::new(),
            next_id: 1000u64
        }
    }

    // 경로 추가
    fn add_route(mut self, destination: IpAddr, netmask: Netmask, gateway: Gateway,
                 metric: Metric, route_type: RouteType, interface: string) -> (RouteTable, RouteID) {
        let route_id = self.next_id
        self.next_id = self.next_id + 1u64

        let route = Route {
            id: route_id,
            destination: destination,
            netmask: netmask,
            gateway: gateway,
            metric: metric,
            route_type: route_type,
            interface: interface,
            created_at: get_timestamp(),
            active: true
        }

        self.routes.push(route)
        (self, route_id)
    }

    // 모든 경로 조회
    fn list_all_routes(ref self) -> Vec<(RouteID, IpAddr, Netmask, Gateway, Metric)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active {
                        result.push((r.id, r.destination, r.netmask, r.gateway, r.metric))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 경로 상세 정보
    fn get_route_details(ref self, route_id: RouteID) -> Option<(IpAddr, Netmask, Gateway, Metric, string, string)> {
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.id == route_id && r.active {
                        let route_type_str = route_type_to_string(r.route_type)
                        return Some((r.destination, r.netmask, r.gateway, r.metric, r.interface, route_type_str))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 경로 삭제 (비활성화)
    fn delete_route(mut self, route_id: RouteID) -> (RouteTable, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.id == route_id {
                        let updated = Route {
                            id: r.id,
                            destination: r.destination,
                            netmask: r.netmask,
                            gateway: r.gateway,
                            metric: r.metric,
                            route_type: r.route_type,
                            interface: r.interface,
                            created_at: r.created_at,
                            active: false
                        }
                        self.routes.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 기본 경로 조회
    fn find_default_route(ref self) -> Option<(RouteID, Gateway, Metric, string)> {
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active {
                        match r.route_type {
                            RouteType::Default => {
                                return Some((r.id, r.gateway, r.metric, r.interface))
                            }
                            _ => {}
                        }
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 목적지별 경로 찾기
    fn find_route_by_destination(ref self, dest: IpAddr) -> Option<(RouteID, Gateway, Metric, string)> {
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active && r.destination == dest {
                        return Some((r.id, r.gateway, r.metric, r.interface))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 인터페이스별 경로 조회
    fn list_routes_by_interface(ref self, iface: string) -> Vec<(RouteID, IpAddr, Netmask, Gateway)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active && r.interface == iface {
                        result.push((r.id, r.destination, r.netmask, r.gateway))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 전체 경로 수
    fn get_route_count(ref self) -> u64 {
        let mut count = 0u64
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active {
                        count = count + 1u64
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        count
    }

    // 경로 타입별 통계
    fn count_by_type(ref self, route_type: RouteType) -> u64 {
        let mut count = 0u64
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active && route_type_match(r.route_type, route_type) {
                        count = count + 1u64
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        count
    }
}

// === 유틸리티 함수 ===

fn get_timestamp() -> Timestamp {
    12345678u64
}

fn route_type_to_string(rt: RouteType) -> string {
    match rt {
        RouteType::Host => "호스트"
        RouteType::Network => "네트워크"
        RouteType::Default => "기본"
        RouteType::Local => "로컬"
    }
}

fn route_type_match(rt1: RouteType, rt2: RouteType) -> bool {
    match rt1 {
        RouteType::Host => match rt2 {
            RouteType::Host => true
            _ => false
        }
        RouteType::Network => match rt2 {
            RouteType::Network => true
            _ => false
        }
        RouteType::Default => match rt2 {
            RouteType::Default => true
            _ => false
        }
        RouteType::Local => match rt2 {
            RouteType::Local => true
            _ => false
        }
    }
}

