// route Phase 2: 경로 추가/삭제 및 수정
// 목표: 동적 경로 관리, 경로 수정, 조건부 경로 관리

// === 타입 정의 ===

type RouteID = u64
type IpAddr = string
type Netmask = string
type Gateway = string
type Metric = u32
type Timestamp = u64

enum RouteType {
    Host
    Network
    Default
    Local
}

enum RouteStatus {
    Active
    Inactive
    Pending
    Failed
}

type Route {
    id: RouteID
    destination: IpAddr
    netmask: Netmask
    gateway: Gateway
    metric: Metric
    route_type: RouteType
    interface: string
    status: RouteStatus
    created_at: Timestamp
    modified_at: Timestamp
}

type RouteTable {
    routes: Vec<Route>
    next_id: RouteID
}

// === RouteTable 구현 ===

impl RouteTable {

    fn new() -> RouteTable {
        RouteTable {
            routes: Vec::new(),
            next_id: 1000u64
        }
    }

    fn add_route(mut self, destination: IpAddr, netmask: Netmask, gateway: Gateway,
                 metric: Metric, route_type: RouteType, interface: string) -> (RouteTable, RouteID) {
        let route_id = self.next_id
        self.next_id = self.next_id + 1u64

        let route = Route {
            id: route_id,
            destination: destination,
            netmask: netmask,
            gateway: gateway,
            metric: metric,
            route_type: route_type,
            interface: interface,
            status: RouteStatus::Active,
            created_at: get_timestamp(),
            modified_at: get_timestamp()
        }

        self.routes.push(route)
        (self, route_id)
    }

    // 경로 수정
    fn update_route(mut self, route_id: RouteID, new_gateway: Gateway, new_metric: Metric) -> (RouteTable, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.id == route_id {
                        let updated = Route {
                            id: r.id,
                            destination: r.destination,
                            netmask: r.netmask,
                            gateway: new_gateway,
                            metric: new_metric,
                            route_type: r.route_type,
                            interface: r.interface,
                            status: r.status,
                            created_at: r.created_at,
                            modified_at: get_timestamp()
                        }
                        self.routes.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 경로 삭제
    fn delete_route(mut self, route_id: RouteID) -> (RouteTable, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.id == route_id {
                        let updated = Route {
                            id: r.id,
                            destination: r.destination,
                            netmask: r.netmask,
                            gateway: r.gateway,
                            metric: r.metric,
                            route_type: r.route_type,
                            interface: r.interface,
                            status: RouteStatus::Inactive,
                            created_at: r.created_at,
                            modified_at: get_timestamp()
                        }
                        self.routes.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 경로 활성화
    fn enable_route(mut self, route_id: RouteID) -> (RouteTable, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.id == route_id {
                        let updated = Route {
                            id: r.id,
                            destination: r.destination,
                            netmask: r.netmask,
                            gateway: r.gateway,
                            metric: r.metric,
                            route_type: r.route_type,
                            interface: r.interface,
                            status: RouteStatus::Active,
                            created_at: r.created_at,
                            modified_at: get_timestamp()
                        }
                        self.routes.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 경로 비활성화
    fn disable_route(mut self, route_id: RouteID) -> (RouteTable, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.id == route_id {
                        let updated = Route {
                            id: r.id,
                            destination: r.destination,
                            netmask: r.netmask,
                            gateway: r.gateway,
                            metric: r.metric,
                            route_type: r.route_type,
                            interface: r.interface,
                            status: RouteStatus::Inactive,
                            created_at: r.created_at,
                            modified_at: get_timestamp()
                        }
                        self.routes.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 활성 경로만 조회
    fn list_active_routes(ref self) -> Vec<(RouteID, IpAddr, Netmask, Gateway, Metric)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    match r.status {
                        RouteStatus::Active => {
                            result.push((r.id, r.destination, r.netmask, r.gateway, r.metric))
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 메트릭으로 최적 경로 찾기
    fn find_best_route(ref self, destination: IpAddr) -> Option<(RouteID, Gateway, Metric, string)> {
        let mut best_route = None
        let mut best_metric = 4294967295u32  // 최대값
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.destination == destination {
                        match r.status {
                            RouteStatus::Active => {
                                if r.metric < best_metric {
                                    best_metric = r.metric
                                    best_route = Some((r.id, r.gateway, r.metric, r.interface))
                                }
                            }
                            _ => {}
                        }
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        best_route
    }

    // 네트워크별 경로 교체
    fn replace_network_routes(mut self, old_gateway: Gateway, new_gateway: Gateway) -> (RouteTable, u64) {
        let mut count = 0u64
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.gateway == old_gateway {
                        let updated = Route {
                            id: r.id,
                            destination: r.destination,
                            netmask: r.netmask,
                            gateway: new_gateway,
                            metric: r.metric,
                            route_type: r.route_type,
                            interface: r.interface,
                            status: r.status,
                            created_at: r.created_at,
                            modified_at: get_timestamp()
                        }
                        self.routes.set(i, updated)
                        count = count + 1u64
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, count)
    }

    // 상태별 경로 조회
    fn list_routes_by_status(ref self, status: RouteStatus) -> Vec<(RouteID, IpAddr, Netmask, string)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if status_match(r.status, status) {
                        result.push((r.id, r.destination, r.netmask, route_status_to_string(r.status)))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 최근 수정된 경로
    fn get_recently_modified_routes(ref self, limit: u64) -> Vec<(RouteID, IpAddr, Timestamp)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    result.push((r.id, r.destination, r.modified_at))
                }
                None => {}
            }

            i = i + 1u64
        }

        // 최근 순으로 정렬 (간단한 버전)
        let mut sorted = result
        let mut i = 0u64

        while i < limit && i < sorted.len() {
            i = i + 1u64
        }

        sorted
    }
}

// === 유틸리티 함수 ===

fn get_timestamp() -> Timestamp {
    12345678u64
}

fn route_status_to_string(status: RouteStatus) -> string {
    match status {
        RouteStatus::Active => "활성"
        RouteStatus::Inactive => "비활성"
        RouteStatus::Pending => "대기"
        RouteStatus::Failed => "실패"
    }
}

fn status_match(s1: RouteStatus, s2: RouteStatus) -> bool {
    match s1 {
        RouteStatus::Active => match s2 {
            RouteStatus::Active => true
            _ => false
        }
        RouteStatus::Inactive => match s2 {
            RouteStatus::Inactive => true
            _ => false
        }
        RouteStatus::Pending => match s2 {
            RouteStatus::Pending => true
            _ => false
        }
        RouteStatus::Failed => match s2 {
            RouteStatus::Failed => true
            _ => false
        }
    }
}

