// route Phase 3: 멀티 경로 및 부하 분산
// 목표: 다중 경로 관리, 부하 분산, 경로 우선순위

// === 타입 정의 ===

type RouteID = u64
type IpAddr = string
type Netmask = string
type Gateway = string
type Metric = u32
type Weight = u32

enum RouteType {
    Host
    Network
    Default
    Local
}

type Route {
    id: RouteID
    destination: IpAddr
    netmask: Netmask
    gateway: Gateway
    metric: Metric
    weight: Weight
    interface: string
    active: bool
}

type RouteGroup {
    destination: IpAddr
    routes: Vec<Route>
    total_weight: Weight
}

type RouteTable {
    routes: Vec<Route>
    route_groups: Vec<RouteGroup>
    next_id: RouteID
}

// === RouteTable 구현 ===

impl RouteTable {

    fn new() -> RouteTable {
        RouteTable {
            routes: Vec::new(),
            route_groups: Vec::new(),
            next_id: 1000u64
        }
    }

    fn add_route(mut self, destination: IpAddr, netmask: Netmask, gateway: Gateway,
                 metric: Metric, weight: Weight, interface: string) -> (RouteTable, RouteID) {
        let route_id = self.next_id
        self.next_id = self.next_id + 1u64

        let route = Route {
            id: route_id,
            destination: destination,
            netmask: netmask,
            gateway: gateway,
            metric: metric,
            weight: weight,
            interface: interface,
            active: true
        }

        self.routes.push(route)
        (self, route_id)
    }

    // 동일 목적지의 다중 경로 조회
    fn find_multipath_routes(ref self, destination: IpAddr) -> Vec<(RouteID, Gateway, Metric, Weight, string)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active && r.destination == destination {
                        result.push((r.id, r.gateway, r.metric, r.weight, r.interface))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 가중치 기반 경로 선택 (부하 분산)
    fn select_route_by_weight(ref self, destination: IpAddr, traffic_id: u64) -> Option<(RouteID, Gateway, string)> {
        let multi_routes = self.find_multipath_routes(destination)

        if multi_routes.len() == 0u64 {
            return None
        }

        // 가중치 합계 계산
        let mut total_weight = 0u32
        let mut i = 0u64
        while i < multi_routes.len() {
            let (_, _, _, weight, _) = multi_routes.get(i).unwrap()
            total_weight = total_weight + weight
            i = i + 1u64
        }

        // 해시 기반으로 경로 선택
        let selection = traffic_id % (total_weight as u64)
        let mut cumulative = 0u64
        let mut i = 0u64

        while i < multi_routes.len() {
            let (id, gw, _, weight, iface) = multi_routes.get(i).unwrap()
            cumulative = cumulative + (weight as u64)

            if selection < cumulative {
                return Some((id, gw, iface))
            }

            i = i + 1u64
        }

        None
    }

    // 우선순위 기반 경로 선택
    fn select_route_by_priority(ref self, destination: IpAddr) -> Option<(RouteID, Gateway, Metric, string)> {
        let multi_routes = self.find_multipath_routes(destination)

        if multi_routes.len() == 0u64 {
            return None
        }

        // 메트릭이 가장 낮은 경로 선택
        let mut best_route = None
        let mut best_metric = 4294967295u32
        let mut i = 0u64

        while i < multi_routes.len() {
            let (id, gw, metric, _, iface) = multi_routes.get(i).unwrap()

            if metric < best_metric {
                best_metric = metric
                best_route = Some((id, gw, metric, iface))
            }

            i = i + 1u64
        }

        best_route
    }

    // 경로 가중치 조정
    fn update_route_weight(mut self, route_id: RouteID, new_weight: Weight) -> (RouteTable, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.id == route_id {
                        let updated = Route {
                            id: r.id,
                            destination: r.destination,
                            netmask: r.netmask,
                            gateway: r.gateway,
                            metric: r.metric,
                            weight: new_weight,
                            interface: r.interface,
                            active: r.active
                        }
                        self.routes.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 목적지별 경로 통계
    fn get_destination_stats(ref self, destination: IpAddr) -> Option<(u64, Weight, u32)> {
        let multi_routes = self.find_multipath_routes(destination)

        if multi_routes.len() == 0u64 {
            return None
        }

        let mut total_weight = 0u32
        let mut min_metric = 4294967295u32
        let mut i = 0u64

        while i < multi_routes.len() {
            let (_, _, metric, weight, _) = multi_routes.get(i).unwrap()

            total_weight = total_weight + weight
            if metric < min_metric {
                min_metric = metric
            }

            i = i + 1u64
        }

        Some((multi_routes.len(), total_weight, min_metric))
    }

    // 부하 분산 상태 조회
    fn get_load_balance_status(ref self, destination: IpAddr) -> Vec<(string, Weight, u32)> {
        let multi_routes = self.find_multipath_routes(destination)
        let mut result = Vec::new()
        let mut i = 0u64

        while i < multi_routes.len() {
            let (_, gw, metric, weight, _) = multi_routes.get(i).unwrap()
            result.push((gw, weight, metric))
            i = i + 1u64
        }

        result
    }

    // 경로 그룹별 조회
    fn list_routes_by_destination_group(ref self) -> Vec<(IpAddr, u64, Weight)> {
        let mut groups = Vec::new()
        let mut processed = Vec::new()
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active {
                        let mut found = false
                        let mut j = 0u64

                        while j < processed.len() {
                            let dest = processed.get(j).unwrap()
                            if dest == r.destination {
                                found = true
                            }
                            j = j + 1u64
                        }

                        if !found {
                            let stats = self.get_destination_stats(r.destination)
                            match stats {
                                Some((count, weight, _)) => {
                                    groups.push((r.destination, count, weight))
                                    processed.push(r.destination)
                                }
                                None => {}
                            }
                        }
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        groups
    }

    // 활성 경로 수
    fn count_active_routes(ref self) -> u64 {
        let mut count = 0u64
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active {
                        count = count + 1u64
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        count
    }
}

