// route Phase 4: 고급 라우팅
// 목표: 정책 기반 라우팅, 라우팅 최적화, 고급 진단

// === 타입 정의 ===

type RouteID = u64
type IpAddr = string
type Netmask = string
type Gateway = string
type Metric = u32
type Weight = u32
type Timestamp = u64

enum RouteType {
    Host
    Network
    Default
    Local
}

enum RoutingPolicy {
    Performance      // 최소 지연
    Reliability      // 신뢰성 우선
    CostOptimized    // 비용 최적화
    FailOver         // 장애 조치
}

type Route {
    id: RouteID
    destination: IpAddr
    netmask: Netmask
    gateway: Gateway
    metric: Metric
    weight: Weight
    interface: string
    policy: RoutingPolicy
    active: bool
    last_used: Timestamp
    use_count: u64
}

type RoutingAnalysis {
    total_routes: u64
    active_routes: u64
    redundant_routes: u64
    total_traffic: u64
    avg_metric: u32
    optimization_score: u32
}

type RouteTable {
    routes: Vec<Route>
    next_id: RouteID
    policy: RoutingPolicy
}

// === RouteTable 구현 ===

impl RouteTable {

    fn new(policy: RoutingPolicy) -> RouteTable {
        RouteTable {
            routes: Vec::new(),
            next_id: 1000u64,
            policy: policy
        }
    }

    fn add_route(mut self, destination: IpAddr, netmask: Netmask, gateway: Gateway,
                 metric: Metric, weight: Weight, interface: string, policy: RoutingPolicy) -> (RouteTable, RouteID) {
        let route_id = self.next_id
        self.next_id = self.next_id + 1u64

        let route = Route {
            id: route_id,
            destination: destination,
            netmask: netmask,
            gateway: gateway,
            metric: metric,
            weight: weight,
            interface: interface,
            policy: policy,
            active: true,
            last_used: get_timestamp(),
            use_count: 0u64
        }

        self.routes.push(route)
        (self, route_id)
    }

    // 정책 기반 경로 선택
    fn select_route_by_policy(mut self, destination: IpAddr) -> Option<(RouteID, Gateway, string)> {
        let mut candidates = Vec::new()
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active && r.destination == destination {
                        candidates.push((r.id, r.gateway, r.interface, r.metric, r.weight))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        if candidates.len() == 0u64 {
            return None
        }

        // 정책에 따라 선택
        let selected = match self.policy {
            RoutingPolicy::Performance => {
                // 메트릭 기반 (지연 최소)
                let mut best = candidates.get(0).unwrap()
                let mut j = 1u64
                while j < candidates.len() {
                    let cand = candidates.get(j).unwrap()
                    if cand.3 < best.3 {
                        best = cand
                    }
                    j = j + 1u64
                }
                best
            }
            RoutingPolicy::Reliability => {
                // 가중치 기반 (신뢰성)
                let mut best = candidates.get(0).unwrap()
                let mut j = 1u64
                while j < candidates.len() {
                    let cand = candidates.get(j).unwrap()
                    if cand.4 > best.4 {
                        best = cand
                    }
                    j = j + 1u64
                }
                best
            }
            RoutingPolicy::CostOptimized => {
                // 가장 첫 번째 경로 (비용 최저)
                candidates.get(0).unwrap()
            }
            RoutingPolicy::FailOver => {
                // 활용도 낮은 경로 선택
                let mut best = candidates.get(0).unwrap()
                let mut j = 1u64
                while j < candidates.len() {
                    let cand = candidates.get(j).unwrap()
                    if cand.0 < best.0 {
                        best = cand
                    }
                    j = j + 1u64
                }
                best
            }
        }

        // 사용 기록 업데이트
        let mut i = 0u64
        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.id == selected.0 {
                        let updated = Route {
                            id: r.id,
                            destination: r.destination,
                            netmask: r.netmask,
                            gateway: r.gateway,
                            metric: r.metric,
                            weight: r.weight,
                            interface: r.interface,
                            policy: r.policy,
                            active: r.active,
                            last_used: get_timestamp(),
                            use_count: r.use_count + 1u64
                        }
                        self.routes.set(i, updated)
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        Some((selected.0, selected.1, selected.2))
    }

    // 중복 경로 탐지
    fn find_redundant_routes(ref self) -> Vec<(IpAddr, u64)> {
        let mut result = Vec::new()
        let mut processed = Vec::new()
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active {
                        let mut found = false
                        let mut j = 0u64

                        while j < processed.len() {
                            let dest = processed.get(j).unwrap()
                            if dest == r.destination {
                                found = true
                            }
                            j = j + 1u64
                        }

                        if !found {
                            // 같은 목적지의 경로 수 계산
                            let mut count = 0u64
                            let mut k = 0u64

                            while k < self.routes.len() {
                                let route2 = self.routes.get(k)

                                match route2 {
                                    Some(r2) => {
                                        if r2.active && r2.destination == r.destination {
                                            count = count + 1u64
                                        }
                                    }
                                    None => {}
                                }

                                k = k + 1u64
                            }

                            if count > 1u64 {
                                result.push((r.destination, count))
                            }

                            processed.push(r.destination)
                        }
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 라우팅 분석
    fn analyze_routing(ref self) -> RoutingAnalysis {
        let mut total_routes = 0u64
        let mut active_routes = 0u64
        let mut total_metric = 0u32
        let mut total_traffic = 0u64
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    total_routes = total_routes + 1u64

                    if r.active {
                        active_routes = active_routes + 1u64
                        total_metric = total_metric + r.metric
                        total_traffic = total_traffic + r.use_count
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        let avg_metric = if active_routes > 0u64 {
            (total_metric as u64 / active_routes) as u32
        } else {
            0u32
        }

        // 최적화 점수 계산 (0-100)
        let redundant = self.find_redundant_routes()
        let redundancy_factor = if redundant.len() > 0u64 {
            (redundant.len() as u32) * 10u32
        } else {
            100u32
        }

        let optimization_score = if redundancy_factor > 100u32 {
            0u32
        } else {
            100u32 - redundancy_factor
        }

        RoutingAnalysis {
            total_routes: total_routes,
            active_routes: active_routes,
            redundant_routes: redundant.len(),
            total_traffic: total_traffic,
            avg_metric: avg_metric,
            optimization_score: optimization_score
        }
    }

    // 최빈 경로 조회
    fn get_most_used_routes(ref self, limit: u64) -> Vec<(RouteID, IpAddr, u64)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.active {
                        result.push((r.id, r.destination, r.use_count))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        // 사용 횟수로 정렬
        let mut sorted = result
        let mut done = false

        while !done {
            done = true
            let mut j = 0u64

            while j + 1u64 < sorted.len() {
                let (_, _, count1) = sorted.get(j).unwrap()
                let (_, _, count2) = sorted.get(j + 1u64).unwrap()

                if count1 < count2 {
                    let temp1 = sorted.get(j).unwrap()
                    let temp2 = sorted.get(j + 1u64).unwrap()
                    sorted.set(j, temp2)
                    sorted.set(j + 1u64, temp1)
                    done = false
                }

                j = j + 1u64
            }
        }

        // 상위 limit개 반환
        let mut top = Vec::new()
        let mut i = 0u64

        while i < limit && i < sorted.len() {
            let item = sorted.get(i)

            match item {
                Some(x) => {
                    top.push(x)
                }
                None => {}
            }

            i = i + 1u64
        }

        top
    }

    // 경로 상태 진단
    fn diagnose_route_health(ref self, route_id: RouteID) -> Option<(bool, string, u32)> {
        let mut i = 0u64

        while i < self.routes.len() {
            let route = self.routes.get(i)

            match route {
                Some(r) => {
                    if r.id == route_id {
                        let is_healthy = r.active && r.metric < 100u32
                        let status = if is_healthy { "정상" } else { "비정상" }
                        let health_score = if r.active {
                            if r.use_count > 0u64 { 100u32 } else { 50u32 }
                        } else {
                            0u32
                        }
                        return Some((is_healthy, status, health_score))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 정책 변경
    fn change_policy(mut self, new_policy: RoutingPolicy) -> RouteTable {
        self.policy = new_policy
        self
    }
}

// === 유틸리티 함수 ===

fn get_timestamp() -> Timestamp {
    12345678u64
}

fn policy_to_string(policy: RoutingPolicy) -> string {
    match policy {
        RoutingPolicy::Performance => "성능 최적화"
        RoutingPolicy::Reliability => "신뢰성 우선"
        RoutingPolicy::CostOptimized => "비용 최적화"
        RoutingPolicy::FailOver => "장애 조치"
    }
}

