// mount Phase 1: 기본 마운트 정보
// 목표: 마운트 정보 조회, 파일시스템 상태

// === 타입 정의 ===

type MountID = u64
type DevicePath = string
type MountPoint = string
type FileSystemType = string
type Timestamp = u64

enum MountStatus {
    Mounted
    Unmounted
    Failed
    Readonly
}

type Mount {
    id: MountID
    device: DevicePath
    mount_point: MountPoint
    filesystem_type: FileSystemType
    status: MountStatus
    mounted_at: Timestamp
    size_total: u64
    size_used: u64
    readonly: bool
}

type MountManager {
    mounts: Vec<Mount>
    next_id: MountID
}

// === MountManager 구현 ===

impl MountManager {

    fn new() -> MountManager {
        MountManager {
            mounts: Vec::new(),
            next_id: 1000u64
        }
    }

    // 마운트 추가
    fn add_mount(mut self, device: DevicePath, mount_point: MountPoint, filesystem_type: FileSystemType,
                 size_total: u64, size_used: u64, readonly: bool) -> (MountManager, MountID) {
        let mount_id = self.next_id
        self.next_id = self.next_id + 1u64

        let mount = Mount {
            id: mount_id,
            device: device,
            mount_point: mount_point,
            filesystem_type: filesystem_type,
            status: MountStatus::Mounted,
            mounted_at: get_timestamp(),
            size_total: size_total,
            size_used: size_used,
            readonly: readonly
        }

        self.mounts.push(mount)
        (self, mount_id)
    }

    // 모든 마운트 조회
    fn list_all_mounts(ref self) -> Vec<(MountID, DevicePath, MountPoint, FileSystemType, u64, u64)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    match m.status {
                        MountStatus::Mounted => {
                            result.push((m.id, m.device, m.mount_point, m.filesystem_type, m.size_total, m.size_used))
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 마운트 포인트별 정보
    fn get_mount_info(ref self, mount_point: MountPoint) -> Option<(MountID, DevicePath, FileSystemType, u64, u64, u64)> {
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.mount_point == mount_point && mount_status_is_mounted(m.status) {
                        let free_space = m.size_total - m.size_used
                        return Some((m.id, m.device, m.filesystem_type, m.size_total, m.size_used, free_space))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 디바이스별 마운트 정보
    fn find_mount_by_device(ref self, device: DevicePath) -> Option<(MountID, MountPoint, FileSystemType, u64, u64)> {
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.device == device {
                        return Some((m.id, m.mount_point, m.filesystem_type, m.size_total, m.size_used))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 파일시스템 타입별 마운트 조회
    fn list_mounts_by_type(ref self, fs_type: FileSystemType) -> Vec<(MountID, DevicePath, MountPoint, u64, u64)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.filesystem_type == fs_type && mount_status_is_mounted(m.status) {
                        result.push((m.id, m.device, m.mount_point, m.size_total, m.size_used))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 사용률 계산
    fn get_usage_percentage(ref self, mount_id: MountID) -> Option<u32> {
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.id == mount_id {
                        if m.size_total == 0u64 {
                            return Some(0u32)
                        }
                        let percent = ((m.size_used * 100u64) / m.size_total) as u32
                        return Some(percent)
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 마운트된 마운트 수
    fn count_mounted(ref self) -> u64 {
        let mut count = 0u64
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    match m.status {
                        MountStatus::Mounted => {
                            count = count + 1u64
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        count
    }

    // 읽기 전용 마운트 조회
    fn list_readonly_mounts(ref self) -> Vec<(MountID, DevicePath, MountPoint)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.readonly && mount_status_is_mounted(m.status) {
                        result.push((m.id, m.device, m.mount_point))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 전체 용량
    fn get_total_capacity(ref self) -> (u64, u64, u64) {
        let mut total_size = 0u64
        let mut total_used = 0u64
        let mut count = 0u64
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if mount_status_is_mounted(m.status) {
                        total_size = total_size + m.size_total
                        total_used = total_used + m.size_used
                        count = count + 1u64
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (total_size, total_used, count)
    }
}

// === 유틸리티 함수 ===

fn get_timestamp() -> Timestamp {
    12345678u64
}

fn mount_status_to_string(status: MountStatus) -> string {
    match status {
        MountStatus::Mounted => "마운트됨"
        MountStatus::Unmounted => "언마운트됨"
        MountStatus::Failed => "실패"
        MountStatus::Readonly => "읽기전용"
    }
}

fn mount_status_is_mounted(status: MountStatus) -> bool {
    match status {
        MountStatus::Mounted => true
        MountStatus::Readonly => true
        _ => false
    }
}

