// mount Phase 2: 마운트/언마운트
// 목표: 마운트 작업, 언마운트, 마운트 옵션 관리

// === 타입 정의 ===

type MountID = u64
type DevicePath = string
type MountPoint = string
type FileSystemType = string
type Timestamp = u64

enum MountStatus {
    Mounted
    Unmounted
    Failed
    Readonly
}

enum MountOption {
    ReadWrite
    ReadOnly
    NoExec
    NoSuid
    NoDev
}

type Mount {
    id: MountID
    device: DevicePath
    mount_point: MountPoint
    filesystem_type: FileSystemType
    status: MountStatus
    mounted_at: Timestamp
    size_total: u64
    size_used: u64
    options: Vec<MountOption>
}

type MountManager {
    mounts: Vec<Mount>
    next_id: MountID
    mount_history: Vec<(Timestamp, string, string)>
}

// === MountManager 구현 ===

impl MountManager {

    fn new() -> MountManager {
        MountManager {
            mounts: Vec::new(),
            next_id: 1000u64,
            mount_history: Vec::new()
        }
    }

    // 마운트 수행
    fn mount(mut self, device: DevicePath, mount_point: MountPoint, filesystem_type: FileSystemType,
             size_total: u64, size_used: u64, options: Vec<MountOption>) -> (MountManager, MountID, bool) {
        let mount_id = self.next_id
        self.next_id = self.next_id + 1u64

        let mount = Mount {
            id: mount_id,
            device: device,
            mount_point: mount_point,
            filesystem_type: filesystem_type,
            status: MountStatus::Mounted,
            mounted_at: get_timestamp(),
            size_total: size_total,
            size_used: size_used,
            options: options
        }

        self.mounts.push(mount)

        // 히스토리에 기록
        let now = get_timestamp()
        self.mount_history.push((now, "mount", mount_point))

        (self, mount_id, true)
    }

    // 언마운트
    fn unmount(mut self, mount_id: MountID) -> (MountManager, bool) {
        let mut found = false
        let mut mount_point_name = ""
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.id == mount_id {
                        mount_point_name = m.mount_point
                        let updated = Mount {
                            id: m.id,
                            device: m.device,
                            mount_point: m.mount_point,
                            filesystem_type: m.filesystem_type,
                            status: MountStatus::Unmounted,
                            mounted_at: m.mounted_at,
                            size_total: m.size_total,
                            size_used: m.size_used,
                            options: m.options
                        }
                        self.mounts.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        if found {
            // 히스토리에 기록
            let now = get_timestamp()
            self.mount_history.push((now, "unmount", mount_point_name))
        }

        (self, found)
    }

    // 재마운트
    fn remount(mut self, mount_id: MountID, new_options: Vec<MountOption>) -> (MountManager, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.id == mount_id {
                        let updated = Mount {
                            id: m.id,
                            device: m.device,
                            mount_point: m.mount_point,
                            filesystem_type: m.filesystem_type,
                            status: m.status,
                            mounted_at: m.mounted_at,
                            size_total: m.size_total,
                            size_used: m.size_used,
                            options: new_options
                        }
                        self.mounts.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 활성 마운트 조회
    fn list_active_mounts(ref self) -> Vec<(MountID, DevicePath, MountPoint)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    match m.status {
                        MountStatus::Mounted => {
                            result.push((m.id, m.device, m.mount_point))
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 마운트 옵션 확인
    fn has_option(ref self, mount_id: MountID, option: MountOption) -> bool {
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.id == mount_id {
                        let mut j = 0u64

                        while j < m.options.len() {
                            let opt = m.options.get(j)

                            match opt {
                                Some(o) => {
                                    if option_match(o, option) {
                                        return true
                                    }
                                }
                                None => {}
                            }

                            j = j + 1u64
                        }
                        return false
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        false
    }

    // 마운트 옵션 문자열
    fn get_mount_options_string(ref self, mount_id: MountID) -> Option<string> {
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.id == mount_id {
                        let mut options_str = ""
                        let mut j = 0u64

                        while j < m.options.len() {
                            let opt = m.options.get(j)

                            match opt {
                                Some(o) => {
                                    let opt_str = option_to_string(o)
                                    if j > 0u64 {
                                        options_str = options_str ++ ","
                                    }
                                    options_str = options_str ++ opt_str
                                }
                                None => {}
                            }

                            j = j + 1u64
                        }

                        return Some(options_str)
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 마운트 히스토리
    fn get_mount_history(ref self, limit: u64) -> Vec<(string, string)> {
        let mut result = Vec::new()
        let history_len = self.mount_history.len()

        let start = if history_len > limit {
            history_len - limit
        } else {
            0u64
        }

        let mut i = start

        while i < history_len {
            let (_, action, mount_point) = self.mount_history.get(i).unwrap()
            result.push((action, mount_point))
            i = i + 1u64
        }

        result
    }

    // 마운트 실패율
    fn get_mount_failure_rate(ref self) -> u32 {
        let mut total = 0u64
        let mut failed = 0u64
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    total = total + 1u64
                    match m.status {
                        MountStatus::Failed => {
                            failed = failed + 1u64
                        }
                        _ => {}
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        if total == 0u64 {
            return 0u32
        }

        ((failed * 100u64) / total) as u32
    }

    // 마운트 강제 해제
    fn force_unmount(mut self, mount_id: MountID) -> (MountManager, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.id == mount_id {
                        let updated = Mount {
                            id: m.id,
                            device: m.device,
                            mount_point: m.mount_point,
                            filesystem_type: m.filesystem_type,
                            status: MountStatus::Unmounted,
                            mounted_at: m.mounted_at,
                            size_total: m.size_total,
                            size_used: m.size_used,
                            options: m.options
                        }
                        self.mounts.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }
}

// === 유틸리티 함수 ===

fn get_timestamp() -> Timestamp {
    12345678u64
}

fn option_to_string(option: MountOption) -> string {
    match option {
        MountOption::ReadWrite => "rw"
        MountOption::ReadOnly => "ro"
        MountOption::NoExec => "noexec"
        MountOption::NoSuid => "nosuid"
        MountOption::NoDev => "nodev"
    }
}

fn option_match(o1: MountOption, o2: MountOption) -> bool {
    match o1 {
        MountOption::ReadWrite => match o2 {
            MountOption::ReadWrite => true
            _ => false
        }
        MountOption::ReadOnly => match o2 {
            MountOption::ReadOnly => true
            _ => false
        }
        MountOption::NoExec => match o2 {
            MountOption::NoExec => true
            _ => false
        }
        MountOption::NoSuid => match o2 {
            MountOption::NoSuid => true
            _ => false
        }
        MountOption::NoDev => match o2 {
            MountOption::NoDev => true
            _ => false
        }
    }
}

