// mount Phase 3: 마운트 옵션 고급 관리
// 목표: 복잡한 마운트 옵션, 마운트 프로필, 성능 최적화

// === 타입 정의 ===

type MountID = u64
type DevicePath = string
type MountPoint = string
type FileSystemType = string
type Timestamp = u64

enum MountOption {
    ReadWrite
    ReadOnly
    NoExec
    NoSuid
    NoDev
    Async
    Sync
    NoAtime
}

type MountProfile {
    name: string
    options: Vec<MountOption>
    max_open_files: u64
    timeout: u32
}

type Mount {
    id: MountID
    device: DevicePath
    mount_point: MountPoint
    filesystem_type: FileSystemType
    mounted_at: Timestamp
    size_total: u64
    size_used: u64
    options: Vec<MountOption>
    profile_name: string
}

type MountManager {
    mounts: Vec<Mount>
    profiles: Vec<MountProfile>
    next_id: MountID
}

// === MountManager 구현 ===

impl MountManager {

    fn new() -> MountManager {
        MountManager {
            mounts: Vec::new(),
            profiles: Vec::new(),
            next_id: 1000u64
        }
    }

    // 마운트 프로필 생성
    fn create_profile(mut self, name: string, options: Vec<MountOption>,
                     max_open_files: u64, timeout: u32) -> MountManager {
        let profile = MountProfile {
            name: name,
            options: options,
            max_open_files: max_open_files,
            timeout: timeout
        }

        self.profiles.push(profile)
        self
    }

    // 프로필 사용 마운트
    fn mount_with_profile(mut self, device: DevicePath, mount_point: MountPoint,
                         filesystem_type: FileSystemType, profile_name: string,
                         size_total: u64, size_used: u64) -> (MountManager, MountID, bool) {
        let mut profile_options = Vec::new()
        let mut found = false
        let mut i = 0u64

        while i < self.profiles.len() {
            let profile = self.profiles.get(i)

            match profile {
                Some(p) => {
                    if p.name == profile_name {
                        profile_options = p.options
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        let mount_id = self.next_id
        self.next_id = self.next_id + 1u64

        let mount = Mount {
            id: mount_id,
            device: device,
            mount_point: mount_point,
            filesystem_type: filesystem_type,
            mounted_at: get_timestamp(),
            size_total: size_total,
            size_used: size_used,
            options: profile_options,
            profile_name: profile_name
        }

        self.mounts.push(mount)
        (self, mount_id, found)
    }

    // 마운트 옵션 추가
    fn add_mount_option(mut self, mount_id: MountID, option: MountOption) -> (MountManager, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.id == mount_id {
                        let mut new_options = m.options
                        new_options.push(option)

                        let updated = Mount {
                            id: m.id,
                            device: m.device,
                            mount_point: m.mount_point,
                            filesystem_type: m.filesystem_type,
                            mounted_at: m.mounted_at,
                            size_total: m.size_total,
                            size_used: m.size_used,
                            options: new_options,
                            profile_name: m.profile_name
                        }
                        self.mounts.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 마운트 옵션 제거
    fn remove_mount_option(mut self, mount_id: MountID, option: MountOption) -> (MountManager, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.id == mount_id {
                        let mut new_options = Vec::new()
                        let mut j = 0u64

                        while j < m.options.len() {
                            let opt = m.options.get(j)

                            match opt {
                                Some(o) => {
                                    if !option_match(o, option) {
                                        new_options.push(o)
                                    }
                                }
                                None => {}
                            }

                            j = j + 1u64
                        }

                        let updated = Mount {
                            id: m.id,
                            device: m.device,
                            mount_point: m.mount_point,
                            filesystem_type: m.filesystem_type,
                            mounted_at: m.mounted_at,
                            size_total: m.size_total,
                            size_used: m.size_used,
                            options: new_options,
                            profile_name: m.profile_name
                        }
                        self.mounts.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 프로필 목록 조회
    fn list_profiles(ref self) -> Vec<(string, u64, u32)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.profiles.len() {
            let profile = self.profiles.get(i)

            match profile {
                Some(p) => {
                    result.push((p.name, p.max_open_files, p.timeout))
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 옵션 조합 조회
    fn get_mount_option_flags(ref self, mount_id: MountID) -> Option<(bool, bool, bool, bool, bool, bool, bool, bool)> {
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.id == mount_id {
                        let mut rw = false
                        let mut ro = false
                        let mut noexec = false
                        let mut nosuid = false
                        let mut nodev = false
                        let mut async_flag = false
                        let mut sync_flag = false
                        let mut noatime = false

                        let mut j = 0u64

                        while j < m.options.len() {
                            let opt = m.options.get(j)

                            match opt {
                                Some(o) => {
                                    match o {
                                        MountOption::ReadWrite => { rw = true }
                                        MountOption::ReadOnly => { ro = true }
                                        MountOption::NoExec => { noexec = true }
                                        MountOption::NoSuid => { nosuid = true }
                                        MountOption::NoDev => { nodev = true }
                                        MountOption::Async => { async_flag = true }
                                        MountOption::Sync => { sync_flag = true }
                                        MountOption::NoAtime => { noatime = true }
                                    }
                                }
                                None => {}
                            }

                            j = j + 1u64
                        }

                        return Some((rw, ro, noexec, nosuid, nodev, async_flag, sync_flag, noatime))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 성능 최적화 프로필
    fn get_performance_profile(ref self) -> Option<MountProfile> {
        let mut i = 0u64

        while i < self.profiles.len() {
            let profile = self.profiles.get(i)

            match profile {
                Some(p) => {
                    if p.name == "performance" {
                        return Some(p)
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 보안 최적화 프로필
    fn get_security_profile(ref self) -> Option<MountProfile> {
        let mut i = 0u64

        while i < self.profiles.len() {
            let profile = self.profiles.get(i)

            match profile {
                Some(p) => {
                    if p.name == "security" {
                        return Some(p)
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 마운트 옵션 호환성 검사
    fn check_option_compatibility(ref self, mount_id: MountID) -> bool {
        let mut i = 0u64

        while i < self.mounts.len() {
            let mount = self.mounts.get(i)

            match mount {
                Some(m) => {
                    if m.id == mount_id {
                        let mut has_rw = false
                        let mut has_ro = false
                        let mut has_async = false
                        let mut has_sync = false

                        let mut j = 0u64

                        while j < m.options.len() {
                            let opt = m.options.get(j)

                            match opt {
                                Some(o) => {
                                    match o {
                                        MountOption::ReadWrite => { has_rw = true }
                                        MountOption::ReadOnly => { has_ro = true }
                                        MountOption::Async => { has_async = true }
                                        MountOption::Sync => { has_sync = true }
                                        _ => {}
                                    }
                                }
                                None => {}
                            }

                            j = j + 1u64
                        }

                        // rw와 ro 동시 불가, async와 sync 동시 불가
                        if (has_rw && has_ro) || (has_async && has_sync) {
                            return false
                        }

                        return true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        false
    }
}

// === 유틸리티 함수 ===

fn get_timestamp() -> Timestamp {
    12345678u64
}

fn option_match(o1: MountOption, o2: MountOption) -> bool {
    match o1 {
        MountOption::ReadWrite => match o2 {
            MountOption::ReadWrite => true
            _ => false
        }
        MountOption::ReadOnly => match o2 {
            MountOption::ReadOnly => true
            _ => false
        }
        MountOption::NoExec => match o2 {
            MountOption::NoExec => true
            _ => false
        }
        MountOption::NoSuid => match o2 {
            MountOption::NoSuid => true
            _ => false
        }
        MountOption::NoDev => match o2 {
            MountOption::NoDev => true
            _ => false
        }
        MountOption::Async => match o2 {
            MountOption::Async => true
            _ => false
        }
        MountOption::Sync => match o2 {
            MountOption::Sync => true
            _ => false
        }
        MountOption::NoAtime => match o2 {
            MountOption::NoAtime => true
            _ => false
        }
    }
}

