    let (mgr2, m2, success) = mgr.mount_with_profile("/dev/sdb1", "/secure", "ext4", "security", 500000000u64, 100000000u64)
    mgr = mgr2
    println!("  /secure (보안): " ++ (if success { "성공" } else { "실패" }))

    // 옵션 플래그 조회
    println!("\n📊 /data 마운트 옵션:")
    let flags = mgr.get_mount_option_flags(m1)
    match flags {
        Some((rw, ro, noexec, nosuid, nodev, async_flag, sync_flag, noatime)) => {
            println!("  rw: " ++ (if rw { "yes" } else { "no" }))
            println!("  ro: " ++ (if ro { "yes" } else { "no" }))
            println!("  noexec: " ++ (if noexec { "yes" } else { "no" }))
            println!("  nosuid: " ++ (if nosuid { "yes" } else { "no" }))
            println!("  nodev: " ++ (if nodev { "yes" } else { "no" }))
            println!("  async: " ++ (if async_flag { "yes" } else { "no" }))
            println!("  sync: " ++ (if sync_flag { "yes" } else { "no" }))
            println!("  noatime: " ++ (if noatime { "yes" } else { "no" }))
        }
        None => {}
    }

    // 옵션 호환성 검사
