    }
}

fn health_match(h1: MountHealth, h2: MountHealth) -> bool {
    match h1 {
        MountHealth::Healthy => match h2 {
            MountHealth::Healthy => true
            _ => false
        }
        MountHealth::Warning => match h2 {
            MountHealth::Warning => true
            _ => false
        }
        MountHealth::Critical => match h2 {
            MountHealth::Critical => true
            _ => false
        }
        MountHealth::Failed => match h2 {
            MountHealth::Failed => true
            _ => false
        }
    }
}

