// fsck Phase 1: 기본 파일시스템 체크
// 목표: 파일시스템 스캔, 기본 에러 감지, 체크 진행 상황

// === 타입 정의 ===

type CheckID = u64
type DevicePath = string
type Timestamp = u64

enum CheckStatus {
    Pending
    Running
    Completed
    Failed
}

enum ErrorType {
    BadBlock
    CorruptedInode
    MissingLink
    InvalidData
}

type FileSystemError {
    error_type: ErrorType
    location: u64
    severity: u32
    description: string
}

type FileSystemCheck {
    id: CheckID
    device: DevicePath
    start_time: Timestamp
    end_time: Timestamp
    status: CheckStatus
    errors_found: Vec<FileSystemError>
    blocks_scanned: u64
    inodes_scanned: u64
}

type FileSystemChecker {
    checks: Vec<FileSystemCheck>
    next_id: CheckID
    current_check: Option<CheckID>
}

// === FileSystemChecker 구현 ===

impl FileSystemChecker {

    fn new() -> FileSystemChecker {
        FileSystemChecker {
            checks: Vec::new(),
            next_id: 1000u64,
            current_check: None
        }
    }

    // 파일시스템 체크 시작
    fn start_check(mut self, device: DevicePath) -> (FileSystemChecker, CheckID) {
        let check_id = self.next_id
        self.next_id = self.next_id + 1u64

        let check = FileSystemCheck {
            id: check_id,
            device: device,
            start_time: get_timestamp(),
            end_time: 0u64,
            status: CheckStatus::Running,
            errors_found: Vec::new(),
            blocks_scanned: 0u64,
            inodes_scanned: 0u64
        }

        self.checks.push(check)
        self.current_check = Some(check_id)

        (self, check_id)
    }

    // 체크 진행률 업데이트
    fn update_progress(mut self, check_id: CheckID, blocks_scanned: u64, inodes_scanned: u64) -> (FileSystemChecker, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.checks.len() {
            let check = self.checks.get(i)

            match check {
                Some(c) => {
                    if c.id == check_id {
                        let updated = FileSystemCheck {
                            id: c.id,
                            device: c.device,
                            start_time: c.start_time,
                            end_time: c.end_time,
                            status: c.status,
                            errors_found: c.errors_found,
                            blocks_scanned: blocks_scanned,
                            inodes_scanned: inodes_scanned
                        }
                        self.checks.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 에러 기록
    fn record_error(mut self, check_id: CheckID, error_type: ErrorType,
                   location: u64, severity: u32, description: string) -> (FileSystemChecker, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.checks.len() {
            let check = self.checks.get(i)

            match check {
                Some(c) => {
                    if c.id == check_id {
                        let mut new_errors = c.errors_found
                        let error = FileSystemError {
                            error_type: error_type,
                            location: location,
                            severity: severity,
                            description: description
                        }
                        new_errors.push(error)

                        let updated = FileSystemCheck {
                            id: c.id,
                            device: c.device,
                            start_time: c.start_time,
                            end_time: c.end_time,
                            status: c.status,
                            errors_found: new_errors,
                            blocks_scanned: c.blocks_scanned,
                            inodes_scanned: c.inodes_scanned
                        }
                        self.checks.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 체크 완료
    fn complete_check(mut self, check_id: CheckID) -> (FileSystemChecker, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.checks.len() {
            let check = self.checks.get(i)

            match check {
                Some(c) => {
                    if c.id == check_id {
                        let updated = FileSystemCheck {
                            id: c.id,
                            device: c.device,
                            start_time: c.start_time,
                            end_time: get_timestamp(),
                            status: CheckStatus::Completed,
                            errors_found: c.errors_found,
                            blocks_scanned: c.blocks_scanned,
                            inodes_scanned: c.inodes_scanned
                        }
                        self.checks.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    // 체크 결과 조회
    fn get_check_result(ref self, check_id: CheckID) -> Option<(DevicePath, u64, u64, u64, CheckStatus)> {
        let mut i = 0u64

        while i < self.checks.len() {
            let check = self.checks.get(i)

            match check {
                Some(c) => {
                    if c.id == check_id {
                        return Some((c.device, c.blocks_scanned, c.inodes_scanned, c.errors_found.len(), c.status))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    // 에러 목록
    fn get_errors_for_check(ref self, check_id: CheckID) -> Vec<(string, u64, u32)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.checks.len() {
            let check = self.checks.get(i)

            match check {
                Some(c) => {
                    if c.id == check_id {
                        let mut j = 0u64

                        while j < c.errors_found.len() {
                            let error = c.errors_found.get(j)

                            match error {
                                Some(e) => {
                                    let error_type = error_type_to_string(e.error_type)
                                    result.push((error_type, e.location, e.severity))
                                }
                                None => {}
                            }

                            j = j + 1u64
                        }
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 최근 체크 목록
    fn get_recent_checks(ref self, limit: u64) -> Vec<(CheckID, DevicePath, u64)> {
        let mut result = Vec::new()
        let checks_len = self.checks.len()

        let start = if checks_len > limit {
            checks_len - limit
        } else {
            0u64
        }

        let mut i = start

        while i < checks_len {
            let check = self.checks.get(i)

            match check {
                Some(c) => {
                    result.push((c.id, c.device, c.errors_found.len()))
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    // 체크 진행률 (퍼센트)
    fn get_progress_percentage(ref self, check_id: CheckID, total_blocks: u64, total_inodes: u64) -> Option<u32> {
        let mut i = 0u64

        while i < self.checks.len() {
            let check = self.checks.get(i)

            match check {
                Some(c) => {
                    if c.id == check_id {
                        let total = total_blocks + total_inodes
                        if total == 0u64 {
                            return Some(0u32)
                        }

                        let scanned = c.blocks_scanned + c.inodes_scanned
                        let percent = ((scanned * 100u64) / total) as u32
                        return Some(percent)
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }
}

// === 유틸리티 함수 ===

fn get_timestamp() -> Timestamp {
    12345678u64
}

fn error_type_to_string(et: ErrorType) -> string {
    match et {
        ErrorType::BadBlock => "나쁜블록"
        ErrorType::CorruptedInode => "손상된아이노드"
        ErrorType::MissingLink => "누락된링크"
        ErrorType::InvalidData => "잘못된데이터"
    }
}

fn check_status_to_string(status: CheckStatus) -> string {
    match status {
        CheckStatus::Pending => "대기중"
        CheckStatus::Running => "진행중"
        CheckStatus::Completed => "완료"
        CheckStatus::Failed => "실패"
    }
}

// === 테스트 ===

fn main() {
    println!("=== fsck Phase 1: 기본 파일시스템 체크 ===")

    let mut checker = FileSystemChecker::new()

    // 체크 시작
    let (checker2, check1) = checker.start_check("/dev/sda1")
    checker = checker2
    println!("✅ /dev/sda1 체크 시작 (ID: " ++ check1.to_string() ++ ")")

    // 진행 상황 업데이트
    let (checker2, success) = checker.update_progress(check1, 100000u64, 50000u64)
    checker = checker2
    println!("✅ 진행 상황 업데이트: " ++ (if success { "성공" } else { "실패" }))

    let (checker2, success) = checker.update_progress(check1, 500000u64, 200000u64)
    checker = checker2

    let (checker2, success) = checker.update_progress(check1, 1000000u64, 400000u64)
    checker = checker2

    // 에러 기록
    println!("\n❌ 에러 기록:")
    let (checker2, success) = checker.record_error(check1, ErrorType::BadBlock, 12345u64, 3u32, "블록 12345 손상")
    checker = checker2
    println!("  에러 1: " ++ (if success { "기록됨" } else { "실패" }))

    let (checker2, success) = checker.record_error(check1, ErrorType::CorruptedInode, 5678u64, 2u32, "아이노드 5678 손상")
    checker = checker2
    println!("  에러 2: " ++ (if success { "기록됨" } else { "실패" }))

    let (checker2, success) = checker.record_error(check1, ErrorType::MissingLink, 9012u64, 1u32, "링크 누락")
    checker = checker2
    println!("  에러 3: " ++ (if success { "기록됨" } else { "실패" }))

    // 진행률
    println!("\n📊 진행률:")
    let progress = checker.get_progress_percentage(check1, 2000000u64, 800000u64)
    match progress {
        Some(p) => {
            println!("  진행률: " ++ p.to_string() ++ "%")
        }
        None => {}
    }

    // 체크 완료
    println!("\n✅ 체크 완료:")
    let (checker2, success) = checker.complete_check(check1)
    checker = checker2
    println!("  완료: " ++ (if success { "성공" } else { "실패" }))

    // 결과 조회
    println!("\n📋 체크 결과:")
    let result = checker.get_check_result(check1)
    match result {
        Some((device, blocks, inodes, errors, status)) => {
            println!("  디바이스: " ++ device)
            println!("  스캔된 블록: " ++ blocks.to_string())
            println!("  스캔된 아이노드: " ++ inodes.to_string())
            println!("  발견된 에러: " ++ errors.to_string())
            println!("  상태: " ++ check_status_to_string(status))
        }
        None => {}
    }

    // 에러 목록
    println!("\n❌ 에러 상세:")
