// fsck Phase 2: 에러 감지
// 목표: 고급 에러 감지, 손상 복구, 자동 수정

type CheckID = u64
type DevicePath = string

enum CheckStatus {
    Pending
    Running
    Completed
    Failed
    Repairing
}

enum ErrorType {
    BadBlock
    CorruptedInode
    MissingLink
    InvalidData
    CrossLink
    OrphanedInode
}

enum RepairAction {
    NoFix
    AutoFix
    Manual
    Skip
}

type FileSystemError {
    error_type: ErrorType
    location: u64
    severity: u32
    repair_action: RepairAction
    fixed: bool
}

type FileSystemCheck {
    id: CheckID
    device: DevicePath
    status: CheckStatus
    errors: Vec<FileSystemError>
    blocks_total: u64
    blocks_bad: u64
    inodes_total: u64
    inodes_bad: u64
}

type FileSystemChecker {
    checks: Vec<FileSystemCheck>
    next_id: CheckID
}

impl FileSystemChecker {

    fn new() -> FileSystemChecker {
        FileSystemChecker {
            checks: Vec::new(),
            next_id: 1000u64
        }
    }

    fn start_check(mut self, device: DevicePath, blocks_total: u64, inodes_total: u64) -> (FileSystemChecker, CheckID) {
        let check_id = self.next_id
        self.next_id = self.next_id + 1u64

        let check = FileSystemCheck {
            id: check_id,
            device: device,
            status: CheckStatus::Running,
            errors: Vec::new(),
            blocks_total: blocks_total,
            blocks_bad: 0u64,
            inodes_total: inodes_total,
            inodes_bad: 0u64
        }

        self.checks.push(check)
        (self, check_id)
    }

    fn detect_error(mut self, check_id: CheckID, error_type: ErrorType, location: u64, severity: u32) -> (FileSystemChecker, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.checks.len() {
            let check = self.checks.get(i)

            match check {
                Some(c) => {
                    if c.id == check_id {
                        let mut new_errors = c.errors

                        let repair_action = match error_type {
                            ErrorType::BadBlock => RepairAction::AutoFix
                            ErrorType::OrphanedInode => RepairAction::AutoFix
                            ErrorType::CorruptedInode => RepairAction::Manual
                            _ => RepairAction::Manual
                        }

                        let error = FileSystemError {
                            error_type: error_type,
                            location: location,
                            severity: severity,
                            repair_action: repair_action,
                            fixed: false
                        }
                        new_errors.push(error)

                        let updated = FileSystemCheck {
                            id: c.id,
                            device: c.device,
                            status: c.status,
                            errors: new_errors,
                            blocks_total: c.blocks_total,
                            blocks_bad: if error_type_is_block(error_type) { c.blocks_bad + 1u64 } else { c.blocks_bad },
                            inodes_total: c.inodes_total,
                            inodes_bad: if error_type_is_inode(error_type) { c.inodes_bad + 1u64 } else { c.inodes_bad }
                        }
                        self.checks.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    fn auto_fix_errors(mut self, check_id: CheckID) -> (FileSystemChecker, u64) {
        let mut fixed_count = 0u64
        let mut i = 0u64

        while i < self.checks.len() {
            let check = self.checks.get(i)

            match check {
                Some(c) => {
                    if c.id == check_id {
                        let mut new_errors = Vec::new()
                        let mut j = 0u64

                        while j < c.errors.len() {
                            let error = c.errors.get(j)

                            match error {
                                Some(e) => {
                                    let can_auto_fix = match e.repair_action {
                                        RepairAction::AutoFix => true
                                        _ => false
                                    }

                                    if can_auto_fix {
                                        let fixed_error = FileSystemError {
                                            error_type: e.error_type,
                                            location: e.location,
                                            severity: e.severity,
                                            repair_action: e.repair_action,
                                            fixed: true
                                        }
                                        new_errors.push(fixed_error)
                                        fixed_count = fixed_count + 1u64
                                    } else {
                                        new_errors.push(e)
                                    }
                                }
                                None => {}
                            }

                            j = j + 1u64
                        }

                        let updated = FileSystemCheck {
                            id: c.id,
                            device: c.device,
                            status: if c.status == CheckStatus::Running { CheckStatus::Repairing } else { c.status },
                            errors: new_errors,
                            blocks_total: c.blocks_total,
                            blocks_bad: c.blocks_bad,
                            inodes_total: c.inodes_total,
                            inodes_bad: c.inodes_bad
                        }
                        self.checks.set(i, updated)
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, fixed_count)
    }

    fn get_unfixed_errors(ref self, check_id: CheckID) -> Vec<(string, u64, RepairAction)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.checks.len() {
            let check = self.checks.get(i)

            match check {
                Some(c) => {
                    if c.id == check_id {
                        let mut j = 0u64

                        while j < c.errors.len() {
                            let error = c.errors.get(j)

                            match error {
                                Some(e) => {
                                    if !e.fixed {
                                        let error_type = error_type_to_string(e.error_type)
                                        result.push((error_type, e.location, e.repair_action))
                                    }
                                }
                                None => {}
                            }

                            j = j + 1u64
                        }
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        result
    }

    fn get_error_summary(ref self, check_id: CheckID) -> Option<(u64, u64, u64, u64)> {
        let mut i = 0u64

        while i < self.checks.len() {
            let check = self.checks.get(i)

