                                    }
                                }
                                None => {}
                            }

                            j = j + 1u64
                        }

                        return Some((total_errors, fixed, c.blocks_bad, c.inodes_bad))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }
}

