        ErrorType::CorruptedInode => "CorruptedInode"
        ErrorType::MissingLink => "MissingLink"
        ErrorType::InvalidData => "InvalidData"
        ErrorType::CrossLink => "CrossLink"
        ErrorType::OrphanedInode => "OrphanedInode"
    }
}

fn error_type_is_block(et: ErrorType) -> bool {
    match et {
