        self.next_id = self.next_id + 1u64

        let copy = DiskCopy {
            id: copy_id,
            source: source,
            destination: destination,
            block_size: block_size,
            total_blocks: total_blocks,
            copied_blocks: 0u64,
            block_errors: Vec::new()
        }

        self.copies.push(copy)
        (self, copy_id)
    }

    fn handle_block_error(mut self, copy_id: CopyID, block_num: u64, error_type: string) -> (DiskDumper, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.copies.len() {
            let copy = self.copies.get(i)

            match copy {
                Some(c) => {
                    if c.id == copy_id {
                        let mut new_errors = c.block_errors
                        let error = BlockError {
                            block_num: block_num,
                            error_type: error_type,
                            skip_count: 0u64
                        }
                        new_errors.push(error)

                        let updated = DiskCopy {
                            id: c.id,
                            source: c.source,
                            destination: c.destination,
                            block_size: c.block_size,
                            total_blocks: c.total_blocks,
                            copied_blocks: c.copied_blocks,
                            block_errors: new_errors
                        }
                        self.copies.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    fn get_error_summary(ref self, copy_id: CopyID) -> Option<(u64, u64)> {
        let mut i = 0u64

        while i < self.copies.len() {
            let copy = self.copies.get(i)

            match copy {
                Some(c) => {
                    if c.id == copy_id {
                        let total_errors = c.block_errors.len()
                        let mut bad_blocks = 0u64

                        let mut j = 0u64
                        while j < c.block_errors.len() {
                            let error = c.block_errors.get(j)

                            match error {
                                Some(e) => {
                                    if e.error_type == "bad_block" {
                                        bad_blocks = bad_blocks + 1u64
                                    }
                                }
                                None => {}
                            }

                            j = j + 1u64
                        }

                        return Some((total_errors, bad_blocks))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }
}

fn main() {
    println!("=== dd Phase 2: 블록 단위 처리 ===")

    let mut dumper = DiskDumper::new()

    let (dumper2, copy1) = dumper.start_copy("/dev/sda", "/dev/sdb", 4096u64, 5000u64)
    dumper = dumper2
    println!("✅ 복사 시작")

    let (dumper2, _) = dumper.handle_block_error(copy1, 100u64, "bad_block")
    dumper = dumper2

    let (dumper2, _) = dumper.handle_block_error(copy1, 500u64, "io_error")
    dumper = dumper2

    let (dumper2, _) = dumper.handle_block_error(copy1, 1000u64, "bad_block")
    dumper = dumper2

    println!("✅ 3개 블록 에러 기록\n")

    let summary = dumper.get_error_summary(copy1)
    match summary {
        Some((total, bad)) => {
            println!("📊 에러 요약:")
            println!("  총 에러: " ++ total.to_string())
            println!("  나쁜 블록: " ++ bad.to_string())
        }
        None => {}
    }
}
