// 목표: 진행 표시, ETA 계산, 통계

type CopyID = u64
type Timestamp = u64

type DiskCopy {
    id: CopyID
    source: string
    destination: string
    block_size: u64
    total_blocks: u64
    copied_blocks: u64
    start_time: Timestamp
    bytes_written: u64
    bytes_per_sec: u64
}

type DiskDumper {
    copies: Vec<DiskCopy>
    next_id: CopyID
}

impl DiskDumper {

    fn new() -> DiskDumper {
        DiskDumper {
            copies: Vec::new(),
            next_id: 1000u64
        }
    }

    fn start_copy(mut self, source: string, destination: string, block_size: u64, total_blocks: u64) -> (DiskDumper, CopyID) {
        let copy_id = self.next_id
        self.next_id = self.next_id + 1u64

        let copy = DiskCopy {
            id: copy_id,
            source: source,
            destination: destination,
            block_size: block_size,
            total_blocks: total_blocks,
            copied_blocks: 0u64,
            start_time: get_timestamp(),
            bytes_written: 0u64,
            bytes_per_sec: 0u64
        }

        self.copies.push(copy)
        (self, copy_id)
    }

    fn update_progress(mut self, copy_id: CopyID, copied_blocks: u64, bytes_written: u64) -> (DiskDumper, bool) {
        let mut found = false
        let mut i = 0u64

        while i < self.copies.len() {
            let copy = self.copies.get(i)

            match copy {
                Some(c) => {
                    if c.id == copy_id {
                        let elapsed = get_timestamp() - c.start_time
                        let bps = if elapsed > 0u64 {
                            bytes_written / elapsed
                        } else {
                            0u64
                        }

                        let updated = DiskCopy {
                            id: c.id,
                            source: c.source,
                            destination: c.destination,
                            block_size: c.block_size,
                            total_blocks: c.total_blocks,
                            copied_blocks: copied_blocks,
                            start_time: c.start_time,
                            bytes_written: bytes_written,
                            bytes_per_sec: bps
                        }
                        self.copies.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    fn get_eta(ref self, copy_id: CopyID) -> Option<u64> {
        let mut i = 0u64

        while i < self.copies.len() {
            let copy = self.copies.get(i)

            match copy {
                Some(c) => {
                    if c.id == copy_id {
                        if c.bytes_per_sec == 0u64 {
                            return Some(0u64)
                        }

                        let remaining_bytes = (c.total_blocks - c.copied_blocks) * c.block_size
                        let eta = remaining_bytes / c.bytes_per_sec
                        return Some(eta)
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    fn get_progress_bar(ref self, copy_id: CopyID) -> Option<(u32, u64)> {
        let mut i = 0u64

        while i < self.copies.len() {
            let copy = self.copies.get(i)

            match copy {
