                    if c.id == copy_id {
                        let percent = if c.total_blocks > 0u64 {
                            ((c.copied_blocks * 100u64) / c.total_blocks) as u32
                        } else {
                            0u32
                        }
                        return Some((percent, c.bytes_per_sec))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }
}

