        (self, archive_id)
    }

    fn get_format_extension(format: CompressionFormat) -> string {
        match format {
            CompressionFormat::Tar => ".tar"
            CompressionFormat::Gzip => ".tar.gz"
            CompressionFormat::Bzip2 => ".tar.bz2"
            CompressionFormat::Xz => ".tar.xz"
        }
    }

    fn compress_with_format(ref self, archive_id: ArchiveID) -> Option<(string, u64)> {
        let mut i = 0u64

        while i < self.archives.len() {
            let archive = self.archives.get(i)

            match archive {
                Some(a) => {
                    if a.id == archive_id {
                        let ext = Self::get_format_extension(a.format)
                        let saved = a.total_size - a.compressed_size
                        return Some((ext, saved))
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }

    fn list_archives_by_format(ref self, format: CompressionFormat) -> Vec<(ArchiveID, string)> {
        let mut result = Vec::new()
        let mut i = 0u64

        while i < self.archives.len() {
            let archive = self.archives.get(i)

            match archive {
