                        return Some(efficiency)
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        None
    }
}

fn format_match(f1: CompressionFormat, f2: CompressionFormat) -> bool {
    match f1 {
        CompressionFormat::Tar => match f2 {
