            _ => false
        }
        CompressionFormat::Bzip2 => match f2 {
            CompressionFormat::Bzip2 => true
            _ => false
        }
        CompressionFormat::Xz => match f2 {
            CompressionFormat::Xz => true
            _ => false
        }
    }
}

