}

impl ArchiveManager {

    fn new() -> ArchiveManager {
        ArchiveManager {
            archives: Vec::new(),
            next_id: 1000u64
        }
    }

    fn create_backup(mut self, path: string, level: BackupLevel) -> (ArchiveManager, ArchiveID) {
        let archive_id = self.next_id
        self.next_id = self.next_id + 1u64

        let archive = Archive {
            id: archive_id,
            path: path,
            backup_level: level,
            entries: Vec::new(),
            created_at: get_timestamp()
        }

        self.archives.push(archive)
        (self, archive_id)
    }

    fn add_backup_entry(mut self, archive_id: ArchiveID, file_path: string,
