        let mut i = 0u64

        while i < self.archives.len() {
            let archive = self.archives.get(i)

            match archive {
                Some(a) => {
                    if a.id == archive_id {
                        let mut new_entries = a.entries
                        let entry = BackupEntry {
                            file_path: file_path,
                            last_modified: last_modified,
                            size: size,
                            backup_level: a.backup_level
                        }
                        new_entries.push(entry)

                        let updated = Archive {
                            id: a.id,
                            path: a.path,
                            backup_level: a.backup_level,
                            entries: new_entries,
                            created_at: a.created_at
                        }
                        self.archives.set(i, updated)
                        found = true
                    }
                }
                None => {}
            }

            i = i + 1u64
        }

        (self, found)
    }

    fn get_backup_summary(ref self, archive_id: ArchiveID) -> Option<(BackupLevel, u64, u64)> {
        let mut i = 0u64

